// Formato Evolution API v2 — n8n wraps o body, mas em alguns casos promove campos à raiz
const webhook = $input.first().json;

// Tenta extrair instanceName de todos os caminhos possíveis
// (depende da versão do n8n e do modo de resposta do webhook)
const instanceName = webhook.instance            // raiz (mais comum)
  || webhook.body?.instance                      // dentro de body
  || webhook.instanceName                        // alias
  || webhook.body?.instanceName                  
  || webhook.data?.instance                      
  || webhook.instanceId                          // UUID como fallback
  || '';

// Tenta extrair fromMe de todos os caminhos
const fromMe = webhook.fromMe 
  || webhook.key?.fromMe 
  || webhook.data?.key?.fromMe 
  || webhook.body?.data?.key?.fromMe 
  || false;

if (fromMe === true) return [];

// remoteJid / sender
const remoteJid = webhook.sender 
  || webhook.remoteJid 
  || webhook.key?.remoteJid
  || webhook.data?.key?.remoteJid 
  || webhook.body?.data?.key?.remoteJid 
  || '';
if (remoteJid.includes('@g.us')) return [];

// Tipo de mensagem
const tipoMensagem = webhook.messageType 
  || webhook.data?.messageType 
  || webhook.body?.data?.messageType 
  || 'conversation';
const TIPOS_IGNORADOS = ['senderKeyDistributionMessage','protocolMessage','reactionMessage','pollUpdateMessage'];
if (TIPOS_IGNORADOS.includes(tipoMensagem)) return [];

const numero = remoteJid.replace('@s.whatsapp.net', '');

// Mensagem de texto — múltiplos caminhos
const mensagem = webhook.conversation
  || webhook.text
  || webhook.body
  || webhook.data?.message?.conversation
  || webhook.data?.message?.extendedTextMessage?.text
  || webhook.body?.data?.message?.conversation
  || '';

const nomeContato = webhook.pushName || webhook.senderName 
  || webhook.data?.pushName || webhook.body?.data?.pushName 
  || 'Lead';

const temArquivo = ['imageMessage','documentMessage','audioMessage','videoMessage','stickerMessage'].includes(tipoMensagem);
const ehAudio = tipoMensagem === 'audioMessage';

// Áudio
let audioBase64 = webhook.mediaBase64 || null;
let audioUrl = webhook.mediaUrl || null;
let audioMimetype = webhook.mimetype || 'audio/ogg';
let audioDuration = webhook.duration || 0;

// Imagem
let ehImagem = tipoMensagem === 'imageMessage';
let imagemUrl = webhook.mediaUrl || null;
let imagemBase64 = webhook.mediaBase64 || null;
let imagemMimetype = webhook.mimetype || 'image/jpeg';
let imagemCaption = webhook.caption || '';

// Documento
let ehDocumento = ['documentMessage','documentWithCaptionMessage'].includes(tipoMensagem);
let docUrl = webhook.mediaUrl || null;
let docBase64 = webhook.mediaBase64 || null;
let docMimetype = webhook.mimetype || 'application/octet-stream';
let docFileName = webhook.fileName || webhook.filename || 'documento';

if (!mensagem && !temArquivo) return [];

return [{ json: { 
  numero, mensagem, nomeContato, tipoMensagem, temArquivo, 
  ehAudio, audioBase64, audioUrl, audioMimetype, audioDuration,
  ehImagem, imagemUrl, imagemBase64, imagemMimetype, imagemCaption,
  ehDocumento, docUrl, docBase64, docMimetype, docFileName,
  instanceName,
  timestamp: new Date().toISOString() 
} }];

const dados = $input.first().json;

// Se temos base64 direto do webhook, usa ele
// Se não, baixa da URL
let audioBase64 = dados.audioBase64;

if (!audioBase64 && dados.audioUrl) {
  try {
    const response = await fetch(dados.audioUrl);
    const arrayBuffer = await response.arrayBuffer();
    const uint8 = new Uint8Array(arrayBuffer);
    let binary = '';
    uint8.forEach(b => binary += String.fromCharCode(b));
    audioBase64 = btoa(binary);
  } catch(e) {
    return [{ json: { ...dados, mensagem: '[Áudio não pôde ser baixado]', ehAudio: false } }];
  }
}

if (!audioBase64) {
  return [{ json: { ...dados, mensagem: '[Áudio sem conteúdo]', ehAudio: false } }];
}

return [{ json: { ...dados, audioBase64 } }];

const dados = $('Normaliza e filtra mensagem').first().json;
const transcricao = $input.first().json.text || '[Transcrição indisponível]';

// Substitui a mensagem pela transcrição e marca como áudio transcrito
return [{ json: { ...dados, mensagem: transcricao, mensagemOriginalAudio: true, ehAudio: true } }];

const rows = $input.first().json; // Array retornado pelo RPC get_agente_config
const config = {};
if (Array.isArray(rows)) {
  rows.forEach(row => { config[row.chave] = row.valor; });
} else if (rows) {
  config[rows.chave] = rows.valor;
}

// Pega dados da mensagem — pode vir do branch texto ou do merge áudio
let dadosMensagem;
try {
  dadosMensagem = $('Merge: áudio → texto').first().json;
} catch(e) {
  dadosMensagem = $('Normaliza e filtra mensagem').first().json;
}

// RPC get_profile_by_instance retorna array
const clienteRaw = $('Resolve cliente pelo instanceName').first().json;
const cliente = Array.isArray(clienteRaw) ? clienteRaw[0] : clienteRaw;
const userId = cliente?.id;
const evoInstance = cliente?.evo_instance || dadosMensagem.instanceName;
const responderEmAudio = config.responder_em_audio === 'true';


// Web search configuration
const webSearchEnabled = config.web_search_enabled !== 'false'; // default true
let webSearchInstructions = '';
if (!webSearchEnabled) {
  webSearchInstructions = '\n\nATENÇÃO: NÃO use a ferramenta de busca na web nesta conversa. Consulte apenas a Base de Conhecimento interna.';
}

// Web URLs de referência
let webUrlsInstructions = '';
try {
  const urls = JSON.parse(config.web_urls_fixas || '[]');
  if (Array.isArray(urls) && urls.length > 0) {
    const lista = urls.map(u => `- ${u.url}${u.desc ? ' ('+u.desc+')' : ''}`).join('\n');
    webUrlsInstructions = `\n\nSITES DE REFERÊNCIA PRIORITÁRIOS (consulte estes antes de outras fontes):\n${lista}`;
  }
} catch(e) {}

const systemPrompt = `${config.prompt_sistema || ''}

OBJETIVO: ${config.objetivo || ''}

TONALIDADE: ${config.tonalidade || ''}

INSTRUÇÕES DE COMUNICAÇÃO: ${config.instrucoes_comunicacao || ''}

CRITÉRIOS DE QUALIFICAÇÃO (precisa atender ao menos 3 dos seguintes):
${config.criterios_qualificacao || ''}

QUANDO O LEAD FOR QUALIFICADO:
- Responda com: ${config.msg_qualificado || 'Vou encaminhar suas informações para o nosso time.'}
- Inclua no final da mensagem um bloco JSON assim:
\`\`\`json
{"qualificado":true,"nome":"Nome completo","celular":"DDD+número","tese":"Produto/Serviço de interesse identificado","resumo":"Resumo completo da conversa"}
\`\`\`

QUANDO O LEAD NÃO FOR QUALIFICADO:
- Responda com: ${config.msg_desqualificado || 'Agradecemos o contato!'}
- Inclua no final:
\`\`\`json
{"qualificado":false,"motivo":"Motivo da desqualificação"}
\`\`\`

REGRAS IMPORTANTES:
- Faça uma pergunta por vez
- Nunca prometa resultado ou vitória
- Se não souber algo, consulte a base de conhecimento antes de responder${webSearchInstructions}${webUrlsInstructions}`;

return [{ json: { ...dadosMensagem, userId, evoInstance, config, systemPrompt, responderEmAudio } }];

const saldoArr = $input.first().json; // Array retornado pelo RPC
const saldo = Array.isArray(saldoArr) ? saldoArr[0] : saldoArr;
const dadosConfig = $('Monta system prompt com config').first().json;

// saldo_tokens pode ser: numero, string, undefined, null
// Se get_token_balance retornou [] (usuario sem registro), saldo = undefined → assume disponível
const saldoRaw = saldo?.saldo_tokens;
const saldoTokens = (saldoRaw !== undefined && saldoRaw !== null) ? Number(saldoRaw) : 1000000;

// Se saldo <= 0, bloqueia e avisa o lead
if (saldoTokens <= 0) {
  return [{ json: { ...dadosConfig, saldoTokens, tokensBloqueado: true, textoParaLead: '⚠️ Olá! No momento nosso sistema está temporariamente indisponível. Por favor, tente novamente mais tarde ou entre em contato pelo número do escritório. Pedimos desculpas pelo inconveniente.' } }];
}

return [{ json: { ...dadosConfig, saldoTokens, tokensBloqueado: false } }];

const dadosConfig = $('Tokens disponíveis?').first().json;
const sessaoArr = $input.first().json; // Array retornado pelo RPC get_sessao
const sessaoRow = Array.isArray(sessaoArr) ? sessaoArr[0] : sessaoArr;

if (sessaoRow?.agente_pausado === true) return [];

let historico = [];
try { historico = JSON.parse(sessaoRow?.historico || '[]'); } catch(e) {}

// Adiciona a mensagem do usuário ao histórico
const prefixo = '';
historico.push({ role: 'user', content: prefixo + dadosConfig.mensagem, type: dadosConfig.ehAudio ? 'audio' : 'text' });

const historicoTexto = historico.map(h => `${h.role === 'user' ? 'Lead' : 'Agente'}: ${h.content}`).join('\n');

return [{ json: { ...dadosConfig, historico, historicoTexto } }];

