const respostaAgente = $input.first().json.output || '';
const configData = $('Monta system prompt com config').first().json;
const dadosMsg = configData;
const config = configData.config;
const userId = configData.userId;
const evoInstance = configData.evoInstance;
const responderEmAudio = configData.responderEmAudio;

let dadosQualificacao = null;
let qualificado = null;

try {
  const match = respostaAgente.match(/```json([\s\S]*?)```/);
  if (match) {
    dadosQualificacao = JSON.parse(match[1].trim());
    qualificado = dadosQualificacao.qualificado === true;
  }
} catch(e) {}

const textoParaLead = respostaAgente.replace(/```json[\s\S]*?```/g, '').trim();

let relatorio = null;
if (qualificado && dadosQualificacao) {
  const agora = new Date().toLocaleString('pt-BR', { timeZone: 'America/Sao_Paulo' });
  relatorio = `🟢 *LEAD QUALIFICADO*\n\n`
    + `👤 *Nome:* ${dadosQualificacao.nome || 'Não informado'}\n`
    + `📱 *Celular:* ${dadosQualificacao.celular || dadosMsg.numero}\n`
    + `🎯 *Interesse:* ${dadosQualificacao.tese || 'Não identificado'}\n`
    + `📋 *Resumo:* ${dadosQualificacao.resumo || 'Ver histórico'}\n`
    + `🕐 *Atendimento:* ${agora}`;
}

// Notif destination config
const notifDestino = config?.notif_destino || 'ambos';
// If only sending to número, zero out grupo so "Tem grupo configurado?" returns false
const grupoDestinoFinal = (notifDestino === 'numero') ? '' : (config?.grupo_destino || '');

return [{ json: { numero: dadosMsg.numero, textoParaLead, qualificado, dadosQualificacao, relatorio, numeroDestino: config?.numero_destino, grupoDestino: grupoDestinoFinal, notifDestino, userId, evoInstance, responderEmAudio } }];

const dados = $('Processa resposta e qualificação').first().json;
const binaryData = $input.first().binary?.data;

if (!binaryData) {
  // Fallback: se TTS falhar, envia texto
  return [{ json: { ...dados, enviarComoAudio: false } }];
}

// Converte binary para base64
const base64Audio = Buffer.from(binaryData.data, 'base64').toString('base64');
const audioDataUri = `data:audio/mp3;base64,${base64Audio}`;

return [{ json: { ...dados, audioResposta: audioDataUri, enviarComoAudio: true } }];

const dados = $('Processa resposta e qualificação').first().json;
const saldoAtual = $('Tokens disponíveis?').first().json.saldoTokens || 0;
const config = $('Monta system prompt com config').first().json.config || {};

// Estimativa bruta de tokens (≈4 chars por token)
const historicoTexto = $('Monta histórico da conversa').first().json.historicoTexto || '';
const systemPrompt = $('Monta system prompt com config').first().json.systemPrompt || '';
const respostaLen = (dados.textoParaLead || '').length;
const tokensRaw = Math.max(500, Math.round((historicoTexto.length + systemPrompt.length + respostaLen) / 4));

// Multiplicador de custo relativo ao gpt-4o-mini (base = 1.0)
// Garante que modelos premium debitam mais créditos proporcionalmente ao custo real
const CUSTO_MODELO = {
  'gpt-4.1-nano':              0.3,
  'gpt-4.1-mini':              0.8,
  'gpt-4.1':                   5.5,
  'gpt-4o-mini':               1.0,
  'gpt-4o':                    8.0,
  'o4-mini':                   2.0,
  'o3-mini':                   3.0,
  'o3':                       12.0,
  'gpt-4-turbo':               6.0,
  'gpt-3.5-turbo':             0.2,
  'claude-haiku-4-5-20251001': 0.9,
  'claude-sonnet-4-6':        10.0,
  'claude-opus-4-6':          50.0,
  'claude-3-5-haiku-20241022':  0.9,
  'claude-3-5-sonnet-20241022':10.0,
  'claude-3-opus-20240229':   40.0,
};

const provider = config.ai_provider || 'openai';
const modeloAtivo = provider === 'claude'
  ? (config.claude_model || 'claude-haiku-4-5-20251001')
  : (config.openai_model || 'gpt-4o-mini');

const multiplicador = CUSTO_MODELO[modeloAtivo] ?? 1.0;
const tokensEstimado = Math.round(tokensRaw * multiplicador);
const novoSaldo = Math.max(0, saldoAtual - tokensEstimado);

return [{ json: { ...dados, tokensUsados: tokensEstimado, novoSaldo, modeloAtivo, multiplicador } }];

const dados = $('Processa resposta e qualificação').first().json;
const numero = dados.numero || '';
const raw = $input.first().json;

// Evolution API pode retornar { participants: [...] } ou array direto
let participants = [];
if (Array.isArray(raw)) {
  participants = raw;
} else if (Array.isArray(raw?.participants)) {
  participants = raw.participants;
}

// Compara número do lead com JIDs dos participantes (5511999@s.whatsapp.net)
const isParticipant = participants.some(p => {
  const jid = (p.id || p.jid || '').split('@')[0];
  return jid === numero || jid === numero.replace(/\D/g, '');
});

return [{ json: { ...dados, isParticipant } }];

const historico = $('Monta histórico da conversa').first().json.historico;
const respostaAgente = $('Agente SDR — IA').first().json.output || '';
const configData = $('Monta system prompt com config').first().json;
const responderEmAudio = configData.responderEmAudio;

historico.push({ role: 'assistant', content: respostaAgente, type: responderEmAudio ? 'audio' : 'text' });
const historicoTrimmed = historico.slice(-20);

return [{ json: { numero_whatsapp: configData.numero, user_id: configData.userId, historico: JSON.stringify(historicoTrimmed), atualizado_em: new Date().toISOString() } }];

const dados = $input.first().json;
const apiKey = $env.OPENAI_API_KEY;

// Monta o conteúdo da mensagem para Vision
const imageContent = dados.imagemBase64
  ? { type: 'image_url', image_url: { url: `data:${dados.imagemMimetype};base64,${dados.imagemBase64}`, detail: 'high' } }
  : dados.imagemUrl
    ? { type: 'image_url', image_url: { url: dados.imagemUrl, detail: 'high' } }
    : null;

if (!imageContent) {
  const descricao = dados.imagemCaption ? `Lead enviou uma imagem com a legenda: "${dados.imagemCaption}"` : 'Lead enviou uma imagem (sem conteúdo disponível)';
  return [{ json: { ...dados, mensagem: descricao, ehImagem: true } }];
}

const messages = [
  { role: 'system', content: 'Você é um assistente que descreve imagens enviadas por clientes para uma empresa. Descreva o que vê na imagem de forma objetiva, mencionando qualquer documento, proposta, contrato, comprovante ou material relevante que apareça. Se for um documento, leia e transcreva o conteúdo principal.' },
  { role: 'user', content: [
    { type: 'text', text: dados.imagemCaption ? `O cliente enviou esta imagem com o comentário: "${dados.imagemCaption}". Descreva e analise.` : 'O cliente enviou esta imagem. Descreva e analise o conteúdo.' },
    imageContent
  ] }
];

const response = await $helpers.request({
  method: 'POST',
  url: 'https://api.openai.com/v1/chat/completions',
  headers: { 'Authorization': `Bearer ${apiKey}`, 'Content-Type': 'application/json' },
  body: JSON.stringify({ model: 'gpt-4o', messages, max_tokens: 1024 }),
  responseType: 'json'
});

const descricao = response.choices?.[0]?.message?.content || 'Imagem recebida mas não foi possível analisar.';
const mensagemFinal = `📷 [Lead enviou uma imagem]:\n${descricao}`;

return [{ json: { ...dados, mensagem: mensagemFinal, ehImagem: true } }];

const dados = $input.first().json;
const apiKey = $env.OPENAI_API_KEY;
const isPdf = dados.docMimetype?.includes('pdf');

if (!dados.docBase64 && !dados.docUrl) {
  const mensagemFinal = `📄 [Lead enviou o arquivo "${dados.docFileName}"]:\n(Arquivo recebido mas sem conteúdo legível disponível. Pergunte ao lead sobre o conteúdo.)`;
  return [{ json: { ...dados, mensagem: mensagemFinal, ehDocumento: true } }];
}

if (isPdf && dados.docBase64) {
  // Chama GPT-4o com o PDF como base64 para extrair texto
  const response = await $helpers.request({
    method: 'POST',
    url: 'https://api.openai.com/v1/chat/completions',
    headers: { 'Authorization': `Bearer ${apiKey}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({
      model: 'gpt-4o',
      messages: [
        { role: 'system', content: 'Você é um assistente que extrai e resume o conteúdo de documentos enviados por clientes. Leia o documento e forneça um resumo objetivo do conteúdo principal, incluindo datas, nomes, valores, códigos ou qualquer informação relevante para o atendimento.' },
        { role: 'user', content: [
          { type: 'text', text: `O cliente enviou o arquivo "${dados.docFileName}". Extraia e resuma o conteúdo principal.` },
          { type: 'file', file: { filename: dados.docFileName, file_data: `data:${dados.docMimetype};base64,${dados.docBase64}` } }
        ] }
      ],
      max_tokens: 2048
    }),
    responseType: 'json'
  });
  const texto = response.choices?.[0]?.message?.content || 'Não foi possível extrair o conteúdo.';
  const mensagemFinal = `📄 [Lead enviou o arquivo "${dados.docFileName}"]:\n${texto}`;
  return [{ json: { ...dados, mensagem: mensagemFinal, ehDocumento: true } }];
}

// Arquivo não-PDF ou sem base64 — menciona ao agente
const mensagemFinal = `📄 [Lead enviou o arquivo "${dados.docFileName}" (${dados.docMimetype})]:\n(Arquivo recebido. Responda ao lead solicitando o conteúdo em formato de texto ou peça que descreva o documento.)`;
return [{ json: { ...dados, mensagem: mensagemFinal, ehDocumento: true } }];

// Unifica todas as rotas (áudio, imagem, documento, texto)
// Cada rota já preparou $json.mensagem corretamente
return [$input.first()];

